insert into public.word_queue
  (position, word, part_of_speech, category, definition, definition2, example, example2, enriched, activation_order)
values
  (1, 'Abstraktion', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Das Herauslösen allgemeiner Merkmale aus vielen einzelnen Fällen.', null, 'Die Abstraktion half ihr, hinter den Beispielen ein gemeinsames Muster zu erkennen.', null, false, null),
  (2, 'Axiom', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Eine grundlegende Annahme, die innerhalb eines Systems nicht weiter bewiesen wird.', null, 'Die gesamte Argumentation beruhte auf dem Axiom, dass gleiche Fälle gleich behandelt werden sollen.', null, false, null),
  (3, 'Deduktion', 'Substantiv', 'Logik und Argumentation', 'Ein Schluss vom Allgemeinen auf einen besonderen Einzelfall.', 'Ein Schluss, bei dem aus allgemeinen Regeln mit Sicherheit ein Einzelfall folgt.', 'Durch Deduktion folgerte er aus der Regel, dass auch dieser Vertrag ungültig sein musste.', 'Aus dem Gesetz leitete der Richter per Deduktion die Entscheidung für diesen konkreten Fall ab.', true, 4),
  (4, 'Phänomenologie', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die genaue Beschreibung dessen, wie etwas erlebt oder wahrgenommen wird.', 'Eine philosophische Methode, die das bewusste Erleben genau so beschreibt, wie es sich unmittelbar zeigt.', 'Die Phänomenologie der Angst untersucht, wie sich Angst für Betroffene unmittelbar anfühlt.', 'Die Phänomenologie fragt nicht, was Farbe physikalisch ist, sondern wie das Sehen von Rot erlebt wird.', true, 1),
  (5, 'Epistemologie', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die Lehre davon, wie Wissen entsteht und wo seine Grenzen liegen.', 'Der Teilbereich der Philosophie, der fragt, was wir überhaupt wissen können und woran sich echtes Wissen erkennen lässt.', 'Die Epistemologie fragt, wann eine Überzeugung wirklich als Wissen gelten kann.', 'In ihrer Vorlesung zur Epistemologie unterschied die Professorin sorgfältig zwischen bloßer Meinung und begründetem Wissen.', true, 11),
  (6, 'Evidenz', 'Substantiv', 'Wissenschaft und Forschung', 'Beobachtungen oder Belege, die eine Aussage stützen.', 'Die Gesamtheit der Belege, die für oder gegen eine Behauptung sprechen.', 'Für die Behauptung fehlte bislang belastbare Evidenz.', 'Für diese Therapie gibt es bislang nur schwache Evidenz aus kleinen Fallzahlen.', true, 5),
  (7, 'Extrapolation', 'Substantiv', 'Wissenschaft und Forschung', 'Das Fortsetzen eines bekannten Verlaufs über den beobachteten Bereich hinaus.', null, 'Die Extrapolation der bisherigen Zahlen ergab eine deutlich höhere Nachfrage im nächsten Jahr.', null, false, null),
  (8, 'Falsifikation', 'Substantiv', 'Wissenschaft und Forschung', 'Der Versuch, eine Aussage durch ein Gegenbeispiel zu widerlegen.', 'Der Nachweis, dass eine Annahme falsch ist, weil eine Beobachtung ihr klar widerspricht.', 'Eine wissenschaftliche Behauptung muss grundsätzlich eine Falsifikation zulassen.', 'Ein einziger schwarzer Schwan genügt zur Falsifikation des Satzes, alle Schwäne seien weiß.', true, 15),
  (9, 'Algorithmik', 'Substantiv', 'Wissenschaft und Forschung', 'Die systematische Entwicklung klarer Rechenschritte zur Lösung von Problemen.', null, 'In der Algorithmik wird nicht nur gefragt, ob eine Lösung funktioniert, sondern auch wie effizient sie ist.', null, false, null),
  (10, 'Explanandum', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Der Sachverhalt, der erklärt werden soll.', null, 'Das plötzliche Absinken der Temperatur war das Explanandum der Untersuchung.', null, false, null),
  (11, 'Bayesianismus', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Eine Denkweise, bei der Überzeugungen nach neuen Hinweisen schrittweise angepasst werden.', null, 'Der Bayesianismus verlangt, neue Daten bei der Einschätzung einer Vermutung fortlaufend zu berücksichtigen.', null, false, null),
  (12, 'Kausalität', 'Substantiv', 'Wissenschaft und Forschung', 'Ein Zusammenhang, bei dem ein Ereignis ein anderes hervorruft.', 'Das Verhältnis von Ursache und Wirkung, bei dem das eine das andere tatsächlich hervorbringt.', 'Die Studie zeigte einen Zusammenhang, bewies aber noch keine Kausalität.', 'Erst ein kontrolliertes Experiment konnte die Kausalität zwischen dem Wirkstoff und der Heilung belegen.', true, 25),
  (13, 'Noetik', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die Lehre vom Denken, Erkennen und geistigen Erfassen.', null, 'Die Noetik beschäftigt sich mit der Frage, wie der menschliche Geist Bedeutung bildet.', null, false, null),
  (14, 'Konstrukt', 'Substantiv', 'Wissenschaft und Forschung', 'Ein gedanklich gebildeter Begriff, der nicht direkt beobachtet werden kann.', 'Ein gedanklich gebildetes Merkmal, das man nicht direkt sehen, sondern nur über Anzeichen erschließen kann.', 'Intelligenz ist ein Konstrukt, das durch verschiedene Aufgaben messbar gemacht wird.', '„Intelligenz“ ist ein Konstrukt, das erst durch Tests fassbar gemacht wird.', true, 35),
  (15, 'Korrelation', 'Substantiv', 'Wissenschaft und Forschung', 'Ein statistischer Zusammenhang zwischen zwei Größen, ohne dass eine Ursache bewiesen ist.', 'Ein statistischer Zusammenhang, bei dem zwei Größen gemeinsam schwanken, ohne dass die eine die andere verursachen muss.', 'Zwischen Schlafdauer und Konzentration bestand eine deutliche Korrelation.', 'Der Verkauf von Speiseeis und die Zahl der Sonnenbrände zeigen eine Korrelation, weil beide vom Wetter abhängen.', true, 45),
  (16, 'Methodologie', 'Substantiv', 'Wissenschaft und Forschung', 'Die Lehre von den Grundsätzen und der Auswahl wissenschaftlicher Methoden.', 'Die begründete Lehre von den Vorgehensweisen, mit denen eine Wissenschaft zu ihren Ergebnissen kommt.', 'Die Methodologie erklärt, warum eine bestimmte Untersuchungsform für die Frage geeignet ist.', 'Ein sauberes Kapitel zur Methodologie erklärt, warum gerade diese Erhebungsmethode gewählt wurde.', true, 55),
  (17, 'Operationalisierung', 'Substantiv', 'Wissenschaft und Forschung', 'Die Übersetzung eines abstrakten Begriffs in konkret messbare Merkmale.', 'Das Übersetzen eines abstrakten Begriffs in konkret messbare Größen.', 'Für die Operationalisierung von Stress wurden Puls, Schlaf und Selbstauskünfte erfasst.', 'Für die Studie wurde „Stress“ durch Operationalisierung als Puls und Cortisolspiegel messbar gemacht.', true, 65),
  (18, 'Episteme', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Das grundlegende Wissens- und Denksystem einer bestimmten Zeit.', null, 'Die Episteme einer Epoche bestimmt mit, welche Fragen überhaupt als sinnvoll gelten.', null, false, null),
  (19, 'Probabilismus', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Eine Haltung, die Entscheidungen auf Wahrscheinlichkeiten statt auf völlige Gewissheit stützt.', null, 'Der Probabilismus akzeptiert, dass vernünftige Urteile auch ohne absolute Sicherheit möglich sind.', null, false, null),
  (20, 'Postulat', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Eine Forderung oder Annahme, die als Ausgangspunkt gesetzt wird.', null, 'Die Gleichheit aller Menschen ist ein zentrales Postulat moderner Rechtsstaaten.', null, false, null),
  (21, 'Prämisse', 'Substantiv', 'Logik und Argumentation', 'Eine Ausgangsaussage, auf der ein Schluss aufgebaut wird.', 'Eine vorausgesetzte Aussage, aus der in einem Argument eine Schlussfolgerung gezogen wird.', 'Wenn die Prämisse falsch ist, kann auch ein formal sauberer Schluss unbrauchbar sein.', 'Wenn schon die erste Prämisse zweifelhaft ist, trägt auch der beste Schluss nicht.', true, 14),
  (22, 'Prognostik', 'Substantiv', 'Wissenschaft und Forschung', 'Die systematische Erstellung begründeter Vorhersagen.', null, 'Die Prognostik nutzt frühere Daten, um mögliche Entwicklungen abzuschätzen.', null, false, null),
  (23, 'Replikation', 'Substantiv', 'Wissenschaft und Forschung', 'Die Wiederholung einer Untersuchung, um ein Ergebnis zu überprüfen.', 'Die erneute Durchführung einer Studie, um zu prüfen, ob sich ihr Ergebnis bestätigt.', 'Erst die erfolgreiche Replikation machte den Befund überzeugender.', 'Erst nach mehrfacher Replikation gilt ein psychologischer Effekt als gut gesichert.', true, 75),
  (24, 'Trennschärfe', 'Substantiv', 'Wissenschaft und Forschung', 'Die Fähigkeit eines Verfahrens, unterschiedliche Fälle zuverlässig auseinanderzuhalten.', null, 'Der Test hatte zu wenig Trennschärfe, weil fast alle Personen ähnlich abschnitten.', null, false, null),
  (25, 'Synopse', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Eine übersichtliche Gegenüberstellung mehrerer Sichtweisen oder Texte.', null, 'Die Synopse machte Gemeinsamkeiten und Unterschiede der drei Entwürfe sofort sichtbar.', null, false, null),
  (26, 'Theorem', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Eine Aussage, die innerhalb eines formalen Systems bewiesen wurde.', null, 'Das Theorem folgt zwingend aus den zuvor festgelegten Annahmen.', null, false, null),
  (27, 'Reliabilität', 'Substantiv', 'Wissenschaft und Forschung', 'Die Zuverlässigkeit einer Messung bei Wiederholung.', 'Die Zuverlässigkeit einer Messung, also ob sie bei Wiederholung stabile Werte liefert.', 'Die Reliabilität des Tests war hoch, weil er bei mehreren Durchläufen ähnliche Ergebnisse lieferte.', 'Eine Waage mit hoher Reliabilität zeigt für dasselbe Gewicht stets nahezu denselben Wert an.', true, 85),
  (28, 'Verifikation', 'Substantiv', 'Wissenschaft und Forschung', 'Die Überprüfung, ob eine Aussage oder ein Ergebnis zutrifft.', 'Die Bestätigung einer Annahme durch Beobachtungen, die zu ihr passen.', 'Vor der Veröffentlichung erfolgte eine unabhängige Verifikation der Zahlen.', 'Die Vorhersage der Planetenbahn diente als Verifikation der neuen Theorie.', true, 95),
  (29, 'Varianz', 'Substantiv', 'Wissenschaft und Forschung', 'Ein Maß dafür, wie stark Werte um ihren Durchschnitt streuen.', 'Ein Maß dafür, wie stark einzelne Messwerte um ihren Durchschnitt streuen.', 'Die große Varianz zeigte, dass die Leistungen der Gruppe sehr unterschiedlich waren.', 'Bei geringer Varianz liegen fast alle Ergebnisse dicht beim Mittelwert.', true, 105),
  (30, 'Intersubjektivität', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Nachvollziehbarkeit eines Urteils für mehrere voneinander unabhängige Personen.', null, 'Wissenschaftliche Ergebnisse sollen durch klare Methoden intersubjektiv überprüfbar sein.', null, false, null),
  (31, 'Introspektion', 'Substantiv', 'Psychologie und Verhalten', 'Die bewusste Beobachtung eigener Gedanken und Gefühle.', null, 'Durch Introspektion bemerkte sie, dass ihre Ablehnung vor allem aus Unsicherheit entstand.', null, false, null),
  (32, 'Metakognition', 'Substantiv', 'Psychologie und Verhalten', 'Das Nachdenken über das eigene Denken und Lernen.', null, 'Metakognition half ihm zu erkennen, warum seine bisherige Lernstrategie nicht funktionierte.', null, false, null),
  (33, 'Kontingenz', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die Eigenschaft, dass etwas so sein kann, aber nicht zwingend so sein muss.', 'Die Eigenschaft von etwas, das ebenso gut auch anders sein könnte und weder notwendig noch unmöglich ist.', 'Der Ausgang war kontingent und hing von mehreren zufälligen Umständen ab.', 'Dass gerade dieser Kandidat gewann, verdankt sich der Kontingenz vieler zufälliger Umstände.', true, 21),
  (34, 'Emergenz', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Das Entstehen neuer Eigenschaften aus dem Zusammenspiel vieler Teile.', null, 'Bewusstsein wird oft als Emergenz komplexer Gehirnprozesse beschrieben.', null, false, null),
  (35, 'Immanenz', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Das Verbleiben innerhalb eines Bereichs oder Systems, ohne darüber hinauszugehen.', 'Das Innewohnen einer Sache in etwas anderem, ohne einen Bezug auf ein Jenseits oder Äußeres.', 'Die Erklärung blieb in der Immanenz des Modells und berücksichtigte keine äußeren Einflüsse.', 'Manche Denker suchen den Sinn in der Immanenz des Lebens selbst statt in einer höheren Ordnung.', true, 31),
  (36, 'Transzendenz', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Das Überschreiten einer gegebenen Grenze oder Erfahrungsebene.', 'Das Überschreiten der Grenzen der sinnlichen Erfahrung hin zu etwas, das darüber hinausliegt.', 'In der Philosophie bezeichnet Transzendenz häufig das Überschreiten des unmittelbar Erfahrbaren.', 'Religiöse Erfahrungen zielen häufig auf eine Transzendenz, die sich der nüchternen Beschreibung entzieht.', true, 41),
  (37, 'Ontologie', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die Lehre davon, was existiert und welche Arten des Seins es gibt.', 'Die Lehre davon, was es grundlegend gibt und in welche Grundarten sich alles Seiende einteilen lässt.', 'Die Ontologie des Modells legt fest, welche Gegenstände und Beziehungen es überhaupt kennt.', 'Ob Zahlen wirklich existieren oder nur nützliche Erfindungen sind, ist eine klassische Frage der Ontologie.', true, 51),
  (38, 'Teleologie', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die Erklärung eines Vorgangs durch seinen Zweck oder sein angestrebtes Ziel.', 'Eine Denkweise, die Dinge von ihrem Zweck oder Ziel her erklärt statt allein von ihren Ursachen.', 'Eine teleologische Deutung erklärt das Verhalten durch den Zweck, den es erfüllen soll.', 'Wer sagt, das Herz sei dazu da, Blut zu pumpen, argumentiert teleologisch.', true, 61),
  (39, 'apriorisch', 'Adjektiv', 'Philosophie und Erkenntnistheorie', 'Unabhängig von konkreter Erfahrung allein aus Denken oder Voraussetzungen abgeleitet.', null, 'Die Aussage wurde apriorisch begründet und nicht aus Beobachtungen gewonnen.', null, false, null),
  (40, 'aposteriorisch', 'Adjektiv', 'Philosophie und Erkenntnistheorie', 'Erst durch Erfahrung oder Beobachtung begründet.', null, 'Die Einschätzung war aposteriorisch, weil sie auf den Ergebnissen des Versuchs beruhte.', null, false, null),
  (41, 'Determinismus', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die Auffassung, dass jedes Ereignis vollständig durch vorherige Bedingungen festgelegt ist.', 'Die Annahme, dass jedes Ereignis vollständig durch vorherige Ursachen festgelegt ist und nichts wirklich zufällig geschieht.', 'Ein strenger Determinismus lässt für echten Zufall kaum Raum.', 'Der strenge Determinismus stellt die Frage, ob unter diesen Bedingungen ein freier Wille überhaupt möglich ist.', true, 71),
  (42, 'Fallibilität', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die grundsätzliche Möglichkeit, sich trotz guter Gründe zu irren.', null, 'Wissenschaft lebt von der Anerkennung menschlicher Fallibilität.', null, false, null),
  (43, 'Holismus', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die Sichtweise, dass ein Ganzes mehr ist als die Summe seiner Einzelteile.', 'Die Auffassung, dass ein Ganzes mehr ist als die Summe seiner Teile und nur im Zusammenhang verstanden werden kann.', 'Der Holismus betrachtet das Team als Beziehungsgefüge und nicht nur als Sammlung einzelner Personen.', 'Aus Sicht des Holismus lässt sich ein Ökosystem nicht begreifen, wenn man nur einzelne Arten isoliert betrachtet.', true, 81),
  (44, 'Reduktionismus', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die Erklärung eines komplexen Sachverhalts allein durch einfachere Bestandteile.', null, 'Der Reduktionismus greift zu kurz, wenn soziale Probleme nur biologisch erklärt werden.', null, false, null),
  (45, 'Essentialismus', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die Annahme, Dinge oder Gruppen hätten einen festen, unveränderlichen Wesenskern.', null, 'Essentialismus kann Unterschiede fälschlich als naturgegeben und unveränderbar darstellen.', null, false, null),
  (46, 'Konstruktivismus', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die Auffassung, dass Menschen Wirklichkeit durch Wahrnehmung und Deutung mitgestalten.', null, 'Der Konstruktivismus betont, dass dieselbe Situation verschieden verstanden werden kann.', null, false, null),
  (47, 'Realismus', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die Auffassung, dass eine von unserem Denken unabhängige Wirklichkeit existiert.', 'Die philosophische Position, dass die Welt unabhängig von unserem Denken und Wahrnehmen existiert.', 'Der wissenschaftliche Realismus nimmt an, dass Theorien reale Strukturen beschreiben können.', 'Der wissenschaftliche Realismus geht davon aus, dass auch unsichtbare Teilchen wie Elektronen wirklich existieren.', true, 91),
  (48, 'Relativismus', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die Auffassung, dass Wahrheit oder Bewertung vom jeweiligen Standpunkt abhängt.', 'Die Ansicht, dass Wahrheit oder Werte nicht absolut gelten, sondern vom jeweiligen Standpunkt abhängen.', 'Ein radikaler Relativismus erschwert die Begründung allgemeiner Maßstäbe.', 'Ein kultureller Relativismus warnt davor, fremde Bräuche vorschnell mit eigenen Maßstäben zu verurteilen.', true, 101),
  (49, 'Universalismus', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die Auffassung, dass bestimmte Regeln oder Rechte für alle Menschen gelten.', null, 'Der Universalismus der Menschenrechte beansprucht Gültigkeit unabhängig von Herkunft und Kultur.', null, false, null),
  (50, 'Partikularismus', 'Substantiv', 'Philosophie und Erkenntnistheorie', 'Die Bevorzugung besonderer Gruppen, Fälle oder Traditionen gegenüber allgemeinen Regeln.', null, 'Partikularismus kann dazu führen, dass für die eigene Gruppe andere Maßstäbe gelten.', null, false, null),
  (51, 'Analogie', 'Substantiv', 'Logik und Argumentation', 'Ein Vergleich zweier Fälle wegen ähnlicher Merkmale oder Strukturen.', 'Eine Übertragung, die von der Ähnlichkeit zweier Fälle auf weitere Gemeinsamkeiten schließt.', 'Die Analogie zum Schach verdeutlichte, warum langfristige Planung wichtiger als ein einzelner Zug ist.', 'Mit der Analogie zum Wasserkreislauf erklärte der Lehrer den Stromfluss im Kabel.', true, 24),
  (52, 'Antinomie', 'Substantiv', 'Logik und Argumentation', 'Ein Widerspruch zwischen zwei scheinbar gleichermaßen begründbaren Aussagen.', 'Ein Widerspruch zwischen zwei Aussagen, die sich beide gleich gut begründen lassen.', 'Die Antinomie entstand, weil Freiheit und vollständige Vorherbestimmung zugleich behauptet wurden.', 'Kant beschrieb die Antinomie, dass die Welt sowohl einen Anfang zu haben als auch keinen haben zu können scheint.', true, 34),
  (53, 'Aporie', 'Substantiv', 'Logik und Argumentation', 'Eine gedankliche Sackgasse, in der keine Lösung widerspruchsfrei erscheint.', null, 'Die Diskussion endete in einer Aporie, weil jede Antwort ein neues Problem erzeugte.', null, false, null),
  (54, 'Binarität', 'Substantiv', 'Logik und Argumentation', 'Die Einteilung in genau zwei klar getrennte Möglichkeiten.', null, 'Die Binarität von richtig und falsch wird komplexen moralischen Fragen oft nicht gerecht.', null, false, null),
  (55, 'Dilemma', 'Substantiv', 'Logik und Argumentation', 'Eine Lage, in der jede verfügbare Entscheidung einen erheblichen Nachteil hat.', 'Eine Zwangslage, in der man zwischen zwei Möglichkeiten wählen muss, die beide unerwünscht sind.', 'Er stand vor dem Dilemma, entweder Zeit oder Qualität zu opfern.', 'Sie steckte im Dilemma, entweder die Freundin zu verraten oder selbst die Schuld zu tragen.', true, 44),
  (56, 'Konsekution', 'Substantiv', 'Logik und Argumentation', 'Eine Folgerung, die sich logisch aus vorherigen Aussagen ergibt.', null, 'Die Konsekution war nur dann zwingend, wenn alle Ausgangsannahmen stimmten.', null, false, null),
  (57, 'Kontradiktion', 'Substantiv', 'Logik und Argumentation', 'Ein direkter Widerspruch, bei dem zwei Aussagen nicht zugleich wahr sein können.', 'Der harte Fall des Widerspruchs, bei dem eine Aussage und ihr genaues Gegenteil zugleich behauptet werden.', 'Zwischen seinen beiden Aussagen bestand eine klare Kontradiktion.', 'Zu sagen, der Kreis sei rund und zugleich eckig, ist eine reine Kontradiktion.', true, 54),
  (58, 'kontrafaktisch', 'Adjektiv', 'Logik und Argumentation', 'Auf eine gedachte Situation bezogen, die tatsächlich nicht eingetreten ist.', null, 'Die kontrafaktische Frage lautete, wie sich alles ohne diese Entscheidung entwickelt hätte.', null, false, null),
  (59, 'Konsistenz', 'Substantiv', 'Logik und Argumentation', 'Widerspruchsfreiheit innerhalb von Aussagen, Regeln oder Handlungen.', null, 'Seiner Position fehlte Konsistenz, weil er bei ähnlichen Fällen verschiedene Maßstäbe anlegte.', null, false, null),
  (60, 'Konsilienz', 'Substantiv', 'Logik und Argumentation', 'Das Zusammenpassen unabhängiger Hinweise oder Forschungsgebiete zu einem gemeinsamen Bild.', null, 'Die Konsilienz der Daten aus Biologie, Psychologie und Soziologie stärkte die Erklärung.', null, false, null),
  (61, 'Konvergenz', 'Substantiv', 'Logik und Argumentation', 'Die Annäherung verschiedener Entwicklungen an einen gemeinsamen Punkt.', null, 'Trotz unterschiedlicher Ausgangslagen zeigte sich eine Konvergenz der Ergebnisse.', null, false, null),
  (62, 'Divergenz', 'Substantiv', 'Logik und Argumentation', 'Das Auseinandergehen von Entwicklungen, Ansichten oder Ergebnissen.', null, 'Die Divergenz zwischen Theorie und Praxis wurde im Verlauf immer größer.', null, false, null),
  (63, 'monokausal', 'Adjektiv', 'Logik und Argumentation', 'Nur auf eine einzige Ursache zurückgeführt.', null, 'Die monokausale Erklärung ignorierte wirtschaftliche, soziale und persönliche Einflüsse.', null, false, null),
  (64, 'multikausal', 'Adjektiv', 'Logik und Argumentation', 'Durch mehrere zusammenwirkende Ursachen entstanden.', null, 'Schulischer Erfolg ist multikausal und lässt sich nicht nur durch Begabung erklären.', null, false, null),
  (65, 'Mutualität', 'Substantiv', 'Logik und Argumentation', 'Ein Verhältnis, in dem beide Seiten wechselseitig geben und empfangen.', null, 'Vertrauen beruht auf Mutualität und kann nicht dauerhaft nur von einer Seite getragen werden.', null, false, null),
  (66, 'Isomorphie', 'Substantiv', 'Logik und Argumentation', 'Eine gleiche Grundstruktur trotz unterschiedlicher Inhalte oder Erscheinungsformen.', null, 'Zwischen den beiden Modellen bestand eine Isomorphie, obwohl sie andere Begriffe verwendeten.', null, false, null),
  (67, 'Tautologie', 'Substantiv', 'Logik und Argumentation', 'Eine Aussage, die denselben Inhalt nur mit anderen Worten wiederholt und nichts erklärt.', 'Eine Aussage, die schon durch ihre Form immer wahr ist und deshalb nichts Neues mitteilt.', 'Die Begründung war eine Tautologie: Es sei richtig, weil es eben das Richtige sei.', '„Morgen regnet es, oder es regnet nicht“ ist eine Tautologie ohne jeden Informationswert.', true, 64),
  (68, 'Zirkelschluss', 'Substantiv', 'Logik und Argumentation', 'Eine Begründung, bei der die zu beweisende Aussage bereits vorausgesetzt wird.', 'Ein Fehler, bei dem das, was bewiesen werden soll, bereits in der Begründung vorausgesetzt wird.', 'Der Satz „Die Quelle ist glaubwürdig, weil sie die Wahrheit sagt“ ist ein Zirkelschluss.', 'Wer die Bibel für wahr hält, weil sie das über sich selbst behauptet, begeht einen Zirkelschluss.', true, 74),
  (69, 'Syllogismus', 'Substantiv', 'Logik und Argumentation', 'Ein formaler Schluss aus zwei Voraussetzungen auf eine Folgerung.', 'Ein klassisches Schlussverfahren, das aus zwei Voraussetzungen zwingend eine dritte Aussage ableitet.', 'Der klassische Syllogismus verbindet eine allgemeine Regel mit einem konkreten Fall.', '„Alle Menschen sind sterblich; Sokrates ist ein Mensch; also ist Sokrates sterblich“ ist der berühmteste Syllogismus.', true, 84),
  (70, 'Subsumtion', 'Substantiv', 'Logik und Argumentation', 'Die Einordnung eines Einzelfalls unter eine allgemeine Regel oder einen Begriff.', null, 'Bei der juristischen Subsumtion wird geprüft, ob der konkrete Fall die Merkmale des Gesetzes erfüllt.', null, false, null),
  (71, 'Abduktion', 'Substantiv', 'Logik und Argumentation', 'Der Schluss von einer Beobachtung auf die wahrscheinlichste Erklärung.', null, 'Aus den nassen Straßen folgerte sie durch Abduktion, dass es geregnet haben könnte.', null, false, null),
  (72, 'Inferenz', 'Substantiv', 'Logik und Argumentation', 'Eine gedankliche Folgerung aus vorhandenen Informationen.', 'Der gedankliche Schritt, mit dem man aus Gegebenem etwas Neues folgert.', 'Die Inferenz war nachvollziehbar, aber nicht zwingend, weil auch andere Erklärungen möglich waren.', 'Aus den Spuren im Schnee zog der Fährtenleser die Inferenz, dass das Tier erst kürzlich vorbeigekommen war.', true, 94),
  (73, 'Invektive', 'Substantiv', 'Sprache und Rhetorik', 'Eine scharfe persönliche Beschimpfung statt einer sachlichen Auseinandersetzung.', null, 'Seine Antwort war keine Kritik mehr, sondern eine Invektive gegen den Gegner.', null, false, null),
  (74, 'Eristik', 'Substantiv', 'Sprache und Rhetorik', 'Die Kunst, einen Streit zu gewinnen, auch ohne inhaltlich recht zu haben.', null, 'Die Eristik des Redners zielte stärker auf Wirkung als auf Wahrheit.', null, false, null),
  (75, 'Sophismus', 'Substantiv', 'Sprache und Rhetorik', 'Ein scheinbar kluger, tatsächlich aber irreführender Gedankengang.', null, 'Der Sophismus klang überzeugend, beruhte jedoch auf einer versteckten Bedeutungsverschiebung.', null, false, null),
  (76, 'Dialektik', 'Substantiv', 'Logik und Argumentation', 'Eine Denkweise, die Gegensätze untersucht und aus ihrer Spannung neue Einsichten gewinnt.', 'Eine Denkbewegung, die aus dem Gegeneinander von These und Gegenthese eine höhere Einsicht gewinnt.', 'Die Dialektik von Freiheit und Sicherheit prägte die gesamte Debatte.', 'In der Dialektik des Gesprächs schärften sich die Positionen erst durch den Widerspruch.', true, 104),
  (77, 'Präzedenzfall', 'Substantiv', 'Recht und Ethik', 'Ein früherer Fall, der als Maßstab für spätere Entscheidungen dient.', 'Ein früherer Fall, dessen Entscheidung als Maßstab für spätere gleichartige Fälle dient.', 'Das Urteil könnte zum Präzedenzfall für ähnliche Verfahren werden.', 'Das Urteil schuf einen Präzedenzfall, auf den sich künftige Kläger berufen konnten.', true, 9),
  (78, 'Proportionalität', 'Substantiv', 'Logik und Argumentation', 'Ein Verhältnis, bei dem sich zwei Größen in einem festen Verhältnis verändern.', null, 'Die Strafe stand nicht in Proportionalität zur geringen Schwere des Fehlers.', null, false, null),
  (79, 'Linearität', 'Substantiv', 'Logik und Argumentation', 'Ein gleichmäßiger Verlauf ohne Sprünge, Rückkopplungen oder Richtungswechsel.', null, 'Die Annahme einer stetigen Linearität unterschätzte plötzliche Wendepunkte.', null, false, null),
  (80, 'Asymmetrie', 'Substantiv', 'Logik und Argumentation', 'Ein unausgeglichenes Verhältnis zwischen zwei Seiten.', null, 'Die Informationsasymmetrie gab dem Verkäufer einen deutlichen Vorteil.', null, false, null),
  (81, 'Komplementarität', 'Substantiv', 'Logik und Argumentation', 'Ein Verhältnis, in dem unterschiedliche Teile einander sinnvoll ergänzen.', null, 'Die Komplementarität ihrer Fähigkeiten machte das Team besonders leistungsfähig.', null, false, null),
  (82, 'Interdependenz', 'Substantiv', 'Logik und Argumentation', 'Eine wechselseitige Abhängigkeit, bei der Veränderungen auf beiden Seiten Folgen haben.', null, 'Die wirtschaftliche Interdependenz erschwerte eine vollständige Trennung der Staaten.', null, false, null),
  (83, 'Ambiguität', 'Substantiv', 'Logik und Argumentation', 'Mehrdeutigkeit eines Wortes, Zeichens oder Sachverhalts.', null, 'Die Ambiguität der Formulierung erlaubte zwei gegensätzliche Deutungen.', null, false, null),
  (84, 'Antagonismus', 'Substantiv', 'Logik und Argumentation', 'Ein grundlegender Gegensatz zwischen Kräften, Interessen oder Gruppen.', null, 'Der Antagonismus zwischen kurzfristigem Gewinn und langfristiger Stabilität blieb ungelöst.', null, false, null),
  (85, 'Inkongruenz', 'Substantiv', 'Logik und Argumentation', 'Ein fehlendes Zusammenpassen von Aussagen, Gefühlen, Formen oder Erwartungen.', null, 'Die Inkongruenz zwischen seinen Worten und seinem Verhalten fiel sofort auf.', null, false, null),
  (86, 'Überdetermination', 'Substantiv', 'Logik und Argumentation', 'Eine Lage, in der mehrere Ursachen unabhängig voneinander dasselbe Ergebnis erklären können.', null, 'Der Konflikt war überdeterminiert, weil wirtschaftliche, persönliche und politische Gründe zusammenwirkten.', null, false, null),
  (87, 'Nuancierung', 'Substantiv', 'Logik und Argumentation', 'Die feinere Abstufung einer zunächst groben Aussage.', null, 'Durch die Nuancierung wurde aus der pauschalen Behauptung eine differenzierte Einschätzung.', null, false, null),
  (88, 'Differenzierung', 'Substantiv', 'Logik und Argumentation', 'Die genaue Unterscheidung ähnlicher, aber nicht gleicher Fälle.', null, 'Ohne Differenzierung wurden berechtigte Kritik und persönliche Angriffe miteinander verwechselt.', null, false, null),
  (89, 'Kategorisierung', 'Substantiv', 'Logik und Argumentation', 'Die Einordnung von Dingen oder Fällen in geordnete Gruppen.', null, 'Die Kategorisierung erleichterte den Überblick, konnte aber Grenzfälle verzerren.', null, false, null),
  (90, 'Taxonomie', 'Substantiv', 'Logik und Argumentation', 'Ein geordnetes System zur Einteilung von Begriffen oder Gegenständen.', null, 'Die Taxonomie ordnete die Fehler nach Ursache, Schwere und Häufigkeit.', null, false, null),
  (91, 'Interpolation', 'Substantiv', 'Wissenschaft und Forschung', 'Die Schätzung eines Wertes zwischen bereits bekannten Messpunkten.', null, 'Durch Interpolation wurde der fehlende Wert zwischen den beiden Messungen angenähert.', null, false, null),
  (92, 'Spezifizität', 'Substantiv', 'Logik und Argumentation', 'Der Grad, in dem eine Aussage oder Methode genau auf einen bestimmten Fall zugeschnitten ist.', null, 'Die hohe Spezifizität der Frage verhinderte ausweichende Antworten.', null, false, null),
  (93, 'Konzision', 'Substantiv', 'Logik und Argumentation', 'Die Fähigkeit, einen Gedanken knapp und ohne unnötige Umwege auszudrücken.', null, 'Die Konzision seiner Zusammenfassung machte den komplizierten Sachverhalt schnell verständlich.', null, false, null),
  (94, 'evident', 'Adjektiv', 'Logik und Argumentation', 'So klar erkennbar, dass kaum vernünftiger Zweifel bleibt.', null, 'Nach dem Vergleich der Daten war der Rechenfehler evident.', null, false, null),
  (95, 'konklusiv', 'Adjektiv', 'Logik und Argumentation', 'So schlüssig, dass eine klare Folgerung daraus gezogen werden kann.', null, 'Die Indizien waren stark, aber noch nicht konklusiv.', null, false, null),
  (96, 'Affekt', 'Substantiv', 'Psychologie und Verhalten', 'Ein starkes, kurzfristiges Gefühl, das Denken und Handeln unmittelbar beeinflusst.', 'Eine kurze, heftige Gefühlsregung, die das Verhalten unmittelbar antreibt.', 'Im Affekt sagte er etwas, das er wenige Minuten später bereute.', 'Im Affekt sagte er Dinge, die er später zutiefst bereute.', true, 2),
  (97, 'Affinität', 'Substantiv', 'Psychologie und Verhalten', 'Eine natürliche Nähe, Neigung oder besondere Verbindung zu etwas.', null, 'Sie zeigte früh eine starke Affinität zu mathematischen Problemen.', null, false, null),
  (98, 'Altruismus', 'Substantiv', 'Psychologie und Verhalten', 'Handeln zum Wohl anderer, auch wenn man selbst keinen direkten Vorteil hat.', null, 'Sein Altruismus zeigte sich darin, dass er anonym einen großen Teil des Gewinns spendete.', null, false, null),
  (99, 'Prolepse', 'Substantiv', 'Psychologie und Verhalten', 'Das gedankliche Vorwegnehmen eines späteren Einwands oder Ereignisses.', null, 'Durch eine Prolepse griff die Rednerin den erwartbaren Einwand auf, bevor er gestellt wurde.', null, false, null),
  (100, 'Attribution', 'Substantiv', 'Psychologie und Verhalten', 'Die Zuschreibung einer Ursache zu einem Verhalten oder Ereignis.', null, 'Ihre Attribution war vorschnell, weil sie den Fehler nur auf mangelnde Motivation zurückführte.', null, false, null),
  (101, 'Aversion', 'Substantiv', 'Psychologie und Verhalten', 'Eine starke Abneigung gegen eine Person, Sache oder Handlung.', 'Eine starke, oft körperlich spürbare Abneigung gegen etwas oder jemanden.', 'Seine Aversion gegen Kontrolle machte selbst hilfreiche Rückmeldungen für ihn schwer annehmbar.', 'Nach der Lebensmittelvergiftung entwickelte sie eine hartnäckige Aversion gegen Muscheln.', true, 12),
  (102, 'Disposition', 'Substantiv', 'Psychologie und Verhalten', 'Eine relativ stabile innere Neigung, auf bestimmte Weise zu reagieren.', null, 'Ihre ruhige Disposition half ihr, auch unter Druck überlegt zu handeln.', null, false, null),
  (103, 'Dissonanz', 'Substantiv', 'Psychologie und Verhalten', 'Ein unangenehmer Widerspruch zwischen Überzeugungen, Gefühlen oder Handlungen.', 'Das unangenehme Spannungsgefühl, wenn Überzeugungen und eigenes Verhalten nicht zusammenpassen.', 'Die Dissonanz entstand, weil er Nachhaltigkeit wichtig fand, aber ständig unnötig konsumierte.', 'Wer raucht und zugleich auf Gesundheit achtet, erlebt eine kognitive Dissonanz.', true, 22),
  (104, 'Dissoziation', 'Substantiv', 'Psychologie und Verhalten', 'Eine zeitweise Trennung von Wahrnehmung, Erinnerung oder Gefühl, die sonst zusammengehören.', null, 'Unter extremer Belastung kann Dissoziation dazu führen, dass sich die Umgebung unwirklich anfühlt.', null, false, null),
  (105, 'Mentalisierung', 'Substantiv', 'Psychologie und Verhalten', 'Die Fähigkeit, eigenes und fremdes Verhalten durch Gedanken, Gefühle und Absichten zu verstehen.', null, 'Gute Mentalisierung half ihr zu erkennen, dass sein Schweigen nicht zwingend Ablehnung bedeutete.', null, false, null),
  (106, 'Externalisierung', 'Substantiv', 'Psychologie und Verhalten', 'Das Verlegen eigener Ursachen oder Konflikte nach außen.', null, 'Durch Externalisierung machte er ausschließlich die Umstände für seine Fehler verantwortlich.', null, false, null),
  (107, 'Internalisierung', 'Substantiv', 'Psychologie und Verhalten', 'Das Übernehmen äußerer Regeln, Werte oder Bewertungen in das eigene Denken.', null, 'Die Internalisierung ständiger Kritik führte dazu, dass sie sich selbst hart beurteilte.', null, false, null),
  (108, 'Habituation', 'Substantiv', 'Psychologie und Verhalten', 'Die allmähliche Gewöhnung an einen wiederkehrenden Reiz.', null, 'Durch Habituation nahm er den Straßenlärm nach einigen Wochen kaum noch wahr.', null, false, null),
  (109, 'Identifikation', 'Substantiv', 'Psychologie und Verhalten', 'Das innere Gleichsetzen mit einer Person, Rolle oder Vorstellung.', null, 'Die Identifikation mit der Hauptfigur verstärkte die emotionale Wirkung des Films.', null, false, null),
  (110, 'Idealisierung', 'Substantiv', 'Psychologie und Verhalten', 'Die übermäßig positive Darstellung, bei der Schwächen ausgeblendet werden.', null, 'Die Idealisierung der Vergangenheit ließ die damaligen Probleme vergessen.', null, false, null),
  (111, 'Idiosynkrasie', 'Substantiv', 'Psychologie und Verhalten', 'Eine sehr persönliche, ungewöhnliche Reaktionsweise oder Eigenart.', null, 'Seine Idiosynkrasie bestand darin, jede Entscheidung zuerst in Tabellen zu ordnen.', null, false, null),
  (112, 'Impulsivität', 'Substantiv', 'Psychologie und Verhalten', 'Die Neigung, schnell zu handeln, ohne Folgen ausreichend zu prüfen.', 'Die Neigung, spontan zu handeln, ohne die Folgen vorher abzuwägen.', 'Hohe Impulsivität kann kurzfristig befreiend wirken, aber langfristig Probleme erzeugen.', 'Seine Impulsivität brachte ihn immer wieder zu übereilten Käufen.', true, 32),
  (113, 'intrinsisch', 'Adjektiv', 'Psychologie und Verhalten', 'Aus eigenem Interesse oder innerem Antrieb heraus.', null, 'Sie lernte intrinsisch motiviert, weil sie das Thema wirklich verstehen wollte.', null, false, null),
  (114, 'extrinsisch', 'Adjektiv', 'Psychologie und Verhalten', 'Durch äußere Belohnung, Druck oder Anerkennung angetrieben.', null, 'Die extrinsische Motivation verschwand, sobald keine Belohnung mehr angeboten wurde.', null, false, null),
  (115, 'Konformität', 'Substantiv', 'Psychologie und Verhalten', 'Die Anpassung des eigenen Verhaltens an Erwartungen einer Gruppe.', 'Die Anpassung des eigenen Verhaltens an die Erwartungen einer Gruppe.', 'Aus Konformität stimmten mehrere Personen zu, obwohl sie innerlich Zweifel hatten.', 'Aus Konformität hob auch sie die Hand, obwohl sie anderer Meinung war.', true, 42),
  (116, 'Resilienz', 'Substantiv', 'Psychologie und Verhalten', 'Die Fähigkeit, Belastungen zu bewältigen und sich davon zu erholen.', 'Die seelische Widerstandskraft, sich von Belastungen zu erholen und daran nicht zu zerbrechen.', 'Ihre Resilienz zeigte sich darin, dass sie nach dem Rückschlag strukturiert neu begann.', 'Ihre Resilienz half ihr, nach dem Rückschlag rasch wieder Fuß zu fassen.', true, 52),
  (117, 'Ressentiment', 'Substantiv', 'Psychologie und Verhalten', 'Ein anhaltender, oft verborgener Groll aus erlebter Kränkung oder Unterlegenheit.', 'Ein lang gehegter, verdeckter Groll, der sich aus gekränktem Stolz oder Neid speist.', 'Sein Ressentiment gegenüber Erfolgreichen prägte viele seiner Urteile.', 'Aus dem alten Ressentiment gegen die Nachbarn wurde über die Jahre offene Feindseligkeit.', true, 62),
  (118, 'Selbstwirksamkeit', 'Substantiv', 'Psychologie und Verhalten', 'Die Überzeugung, durch eigenes Handeln etwas bewirken zu können.', 'Die Überzeugung, schwierige Aufgaben aus eigener Kraft bewältigen zu können.', 'Jeder kleine Erfolg stärkte ihre Selbstwirksamkeit.', 'Jeder gemeisterte Auftritt stärkte ihre Selbstwirksamkeit ein Stück weiter.', true, 72),
  (119, 'Sozialisation', 'Substantiv', 'Psychologie und Verhalten', 'Der Prozess, in dem Menschen Regeln, Werte und Verhaltensweisen ihrer Umgebung erlernen.', 'Der lebenslange Prozess, in dem ein Mensch die Regeln und Werte seiner Umgebung übernimmt.', 'Familie, Schule und Freundeskreis prägen die Sozialisation eines Menschen.', 'Durch die Sozialisation im Elternhaus lernte er früh, Konflikte im Gespräch zu lösen.', true, 82),
  (120, 'Stigmatisierung', 'Substantiv', 'Psychologie und Verhalten', 'Die abwertende Kennzeichnung einer Person oder Gruppe durch ein negatives Merkmal.', null, 'Die Stigmatisierung psychischer Probleme hält manche Menschen davon ab, Hilfe zu suchen.', null, false, null),
  (121, 'Sublimierung', 'Substantiv', 'Psychologie und Verhalten', 'Die Umwandlung belastender oder unerwünschter Impulse in gesellschaftlich akzeptierte Leistungen.', null, 'Er verwandelte seine Aggression durch Sublimierung in intensives sportliches Training.', null, false, null),
  (122, 'Suggestion', 'Substantiv', 'Psychologie und Verhalten', 'Eine Beeinflussung, durch die eine Vorstellung ohne gründliche Prüfung übernommen wird.', null, 'Die suggestive Frage erzeugte eine Suggestion, obwohl die Erinnerung unsicher war.', null, false, null),
  (123, 'Ambiguitätstoleranz', 'Substantiv', 'Psychologie und Verhalten', 'Die Fähigkeit, Mehrdeutigkeit und Unsicherheit auszuhalten, ohne vorschnell zu urteilen.', null, 'Hohe Ambiguitätstoleranz half ihr, widersprüchliche Informationen zunächst nebeneinander stehen zu lassen.', null, false, null),
  (124, 'Kompensation', 'Substantiv', 'Psychologie und Verhalten', 'Der Ausgleich einer Schwäche oder Belastung durch eine andere Leistung oder Strategie.', 'Der Ausgleich einer empfundenen Schwäche durch besondere Anstrengung an anderer Stelle.', 'Er suchte Anerkennung im Beruf als Kompensation für sein geringes Selbstwertgefühl.', 'Als Kompensation für seine Schüchternheit stürzte er sich mit Eifer in die Arbeit.', true, 92),
  (125, 'Projektion', 'Substantiv', 'Psychologie und Verhalten', 'Das Zuschreiben eigener Gefühle oder Wünsche an andere Personen.', 'Das unbewusste Zuschreiben eigener Gefühle oder Fehler an andere Menschen.', 'Seine Behauptung, alle seien neidisch, wirkte wie eine Projektion seiner eigenen Unsicherheit.', 'Seine ständigen Betrugsvorwürfe waren womöglich eine Projektion des eigenen schlechten Gewissens.', true, 102),
  (126, 'Rationalisierung', 'Substantiv', 'Psychologie und Verhalten', 'Eine nachträgliche scheinbar vernünftige Begründung für ein eigentlich anders motiviertes Verhalten.', null, 'Die angebliche Zeitersparnis war nur eine Rationalisierung für seine Bequemlichkeit.', null, false, null),
  (127, 'Regression', 'Substantiv', 'Psychologie und Verhalten', 'Die Rückkehr zu früheren, einfacheren Verhaltensweisen unter Belastung.', null, 'Unter starkem Stress zeigte er eine Regression und reagierte ungewöhnlich kindlich.', null, false, null),
  (128, 'Reaktanz', 'Substantiv', 'Psychologie und Verhalten', 'Innerer Widerstand, der entsteht, wenn die eigene Freiheit eingeschränkt wirkt.', null, 'Das strikte Verbot löste Reaktanz aus und machte die verbotene Sache erst interessant.', null, false, null),
  (129, 'Konditionierung', 'Substantiv', 'Psychologie und Verhalten', 'Das Erlernen einer Reaktion durch wiederholte Verbindung mit einem Reiz oder einer Folge.', null, 'Durch Konditionierung verband der Hund das Geräusch mit der bevorstehenden Fütterung.', null, false, null),
  (130, 'dispositionell', 'Adjektiv', 'Psychologie und Verhalten', 'Auf eine relativ stabile persönliche Neigung zurückgeführt.', null, 'Die dispositionelle Erklärung sah die Ursache vor allem in seinem Charakter.', null, false, null),
  (131, 'Volition', 'Substantiv', 'Psychologie und Verhalten', 'Die bewusste Steuerung des eigenen Handelns trotz Ablenkung oder Widerstand.', null, 'Motivation brachte ihn zum Start, aber Volition hielt ihn bei der Aufgabe.', null, false, null),
  (132, 'Perzeption', 'Substantiv', 'Psychologie und Verhalten', 'Die Aufnahme und Deutung von Sinneseindrücken.', null, 'Die Perzeption derselben Szene unterschied sich je nach Erwartung der Beobachter.', null, false, null),
  (133, 'Prädisposition', 'Substantiv', 'Psychologie und Verhalten', 'Eine vorhandene Anlage oder erhöhte Bereitschaft für eine bestimmte Entwicklung.', null, 'Eine genetische Prädisposition bedeutet nicht, dass eine Erkrankung zwangsläufig ausbricht.', null, false, null),
  (134, 'Behaviorismus', 'Substantiv', 'Psychologie und Verhalten', 'Eine psychologische Richtung, die vor allem beobachtbares Verhalten und Lernprozesse untersucht.', null, 'Der Behaviorismus erklärt Lernen häufig durch Reize, Reaktionen und Folgen.', null, false, null),
  (135, 'Intention', 'Substantiv', 'Psychologie und Verhalten', 'Die bewusste Absicht hinter einer Handlung.', null, 'Die gute Intention änderte nichts daran, dass die Handlung negative Folgen hatte.', null, false, null),
  (136, 'Autonomie', 'Substantiv', 'Recht und Ethik', 'Die Fähigkeit und das Recht, selbstbestimmt zu entscheiden und zu handeln.', 'Die Fähigkeit und das Recht, sich nach selbst gegebenen Regeln zu bestimmen.', 'Echte Autonomie setzt voraus, dass eine Entscheidung ohne unangemessenen Druck getroffen werden kann.', 'Die ärztliche Ethik achtet die Autonomie des Patienten bei jeder Behandlungsentscheidung.', true, 19),
  (137, 'Autoritarismus', 'Substantiv', 'Politik und Gesellschaft', 'Eine politische oder soziale Haltung, die starke Führung und wenig Widerspruch bevorzugt.', null, 'Autoritarismus zeigt sich häufig in der Abwertung offener Kritik und unabhängiger Kontrolle.', null, false, null),
  (138, 'Hegemonie', 'Substantiv', 'Politik und Gesellschaft', 'Eine überlegene Stellung, durch die eine Gruppe Regeln und Vorstellungen prägen kann.', 'Die überlegene Vormacht eines Akteurs, die weniger auf Zwang als auf Führung und Zustimmung beruht.', 'Die kulturelle Hegemonie zeigte sich darin, dass eine Sichtweise als selbstverständlich galt.', 'Nach dem Krieg festigte die Großmacht ihre wirtschaftliche Hegemonie über die Region.', true, 6),
  (139, 'Ideologie', 'Substantiv', 'Politik und Gesellschaft', 'Ein geschlossenes System von Vorstellungen darüber, wie Gesellschaft und Wirklichkeit zu verstehen sind.', 'Ein geschlossenes System von Ideen, das Gesellschaft deutet und politisches Handeln begründet.', 'Die Ideologie beeinflusste nicht nur politische Ziele, sondern auch die Auswahl der Fakten.', 'Hinter dem Programm stand eine klare Ideologie von Markt und Eigenverantwortung.', true, 16),
  (140, 'Legitimität', 'Substantiv', 'Politik und Gesellschaft', 'Die anerkannte Rechtmäßigkeit oder moralische Berechtigung von Macht und Entscheidungen.', 'Die Anerkennung von Herrschaft als rechtmäßig und deshalb zu Recht gehorchenswert.', 'Eine Wahl verleiht politischer Macht Legitimität, ersetzt aber nicht jede weitere Kontrolle.', 'Ohne freie Wahlen fehlte der Regierung in den Augen vieler die Legitimität.', true, 26),
  (141, 'Meritokratie', 'Substantiv', 'Wirtschaft und Organisation', 'Eine Ordnung, in der Stellung und Chancen hauptsächlich nach Leistung vergeben werden sollen.', 'Eine Ordnung, in der Position und Aufstieg an Leistung und Können geknüpft sein sollen.', 'Die Vorstellung einer Meritokratie wird problematisch, wenn Startbedingungen stark ungleich sind.', 'Kritiker der Meritokratie fragen, ob Startchancen wirklich für alle gleich sind.', true, 7),
  (142, 'Pluralismus', 'Substantiv', 'Politik und Gesellschaft', 'Das gleichzeitige Bestehen unterschiedlicher Interessen, Werte und Lebensformen.', 'Die Anerkennung und geordnete Koexistenz vieler unterschiedlicher Meinungen und Gruppen.', 'Politischer Pluralismus schützt die Möglichkeit, öffentlich verschiedene Positionen zu vertreten.', 'Ein lebendiger Pluralismus erträgt es, dass konkurrierende Weltbilder nebeneinander bestehen.', true, 36),
  (143, 'Populismus', 'Substantiv', 'Politik und Gesellschaft', 'Eine politische Strategie, die ein einheitliches Volk gegen angebliche Eliten stellt und Probleme stark vereinfacht.', 'Ein politischer Stil, der ein „reines Volk“ gegen „die Eliten“ ausspielt und einfache Lösungen verspricht.', 'Der Populismus der Rede reduzierte ein vielschichtiges Problem auf einen einzigen Schuldigen.', 'Der Populismus der Rede bestand darin, komplexe Probleme auf einen einzigen Schuldigen zu verengen.', true, 46),
  (144, 'Totalitarismus', 'Substantiv', 'Politik und Gesellschaft', 'Eine Herrschaftsform, die Staat, Gesellschaft und Privatleben möglichst vollständig kontrollieren will.', 'Eine Herrschaftsform, die das gesamte Leben der Menschen durchdringen und kontrollieren will.', 'Totalitarismus duldet kaum unabhängige Medien, Organisationen oder abweichende Weltbilder.', 'Im Totalitarismus gibt es keinen Bereich, der dem Zugriff des Staates entzogen bliebe.', true, 56),
  (145, 'Subsidiarität', 'Substantiv', 'Wirtschaft und Organisation', 'Das Prinzip, Aufgaben möglichst auf der kleinsten handlungsfähigen Ebene zu lösen.', 'Der Grundsatz, dass die jeweils kleinere Einheit entscheidet, solange sie es selbst kann.', 'Nach dem Prinzip der Subsidiarität soll die Gemeinde entscheiden, solange sie die Aufgabe selbst bewältigen kann.', 'Nach dem Prinzip der Subsidiarität regelt die Gemeinde, was sie ohne den Bund bewältigt.', true, 17),
  (146, 'Partizipation', 'Substantiv', 'Politik und Gesellschaft', 'Die aktive Beteiligung an Entscheidungen oder gesellschaftlichen Prozessen.', 'Die aktive Teilhabe der Bürger an Entscheidungen, die sie betreffen.', 'Die frühe Partizipation der Betroffenen erhöhte die Akzeptanz des Projekts.', 'Ein Bürgerhaushalt soll die Partizipation an der kommunalen Finanzplanung stärken.', true, 66),
  (147, 'Emanzipation', 'Substantiv', 'Kultur und Geschichte', 'Die Befreiung aus Abhängigkeit, Bevormundung oder rechtlicher Benachteiligung.', 'Die Befreiung aus Abhängigkeit und Bevormundung hin zu Selbstbestimmung.', 'Bildung spielte eine zentrale Rolle bei der Emanzipation zuvor ausgeschlossener Gruppen.', 'Die Emanzipation der Arbeiterschaft begann mit dem Recht, sich zu organisieren.', true, 8),
  (148, 'Exklusion', 'Substantiv', 'Politik und Gesellschaft', 'Der Ausschluss von Personen oder Gruppen aus Teilhabe und Zugehörigkeit.', null, 'Hohe Gebühren können zu sozialer Exklusion führen.', null, false, null),
  (149, 'Inklusion', 'Substantiv', 'Politik und Gesellschaft', 'Die gleichberechtigte Einbeziehung unterschiedlicher Menschen in gemeinsame Strukturen.', null, 'Inklusion bedeutet mehr als Anwesenheit; sie verlangt echte Mitwirkung und Zugänglichkeit.', null, false, null),
  (150, 'Assimilation', 'Substantiv', 'Kultur und Geschichte', 'Die weitgehende Anpassung an eine andere Gruppe, bei der eigene Merkmale zurücktreten.', 'Die weitgehende Angleichung einer Gruppe an die Kultur der Mehrheit bis zur Aufgabe eigener Merkmale.', 'Assimilation geht weiter als Integration, weil Unterschiede möglichst verschwinden sollen.', 'Die dritte Generation war durch Assimilation kaum noch von der Umgebung zu unterscheiden.', true, 18),
  (151, 'Akkulturation', 'Substantiv', 'Kultur und Geschichte', 'Die Veränderung von Gewohnheiten und Vorstellungen durch längeren Kontakt zwischen Kulturen.', 'Der wechselseitige Kulturwandel, wenn zwei Gruppen über längere Zeit in Kontakt stehen.', 'Akkulturation kann in beide Richtungen wirken und neue Mischformen hervorbringen.', 'Die Akkulturation zeigte sich in einer Küche, die Zutaten beider Herkünfte verband.', true, 28),
  (152, 'Säkularisierung', 'Substantiv', 'Kultur und Geschichte', 'Der Rückgang religiöser Bindung oder religiösen Einflusses auf öffentliche Bereiche.', 'Das Zurückdrängen religiöser Deutung und Institutionen aus dem öffentlichen Leben.', 'Die Säkularisierung veränderte das Verhältnis zwischen Staat, Gesellschaft und Kirchen.', 'Mit der Säkularisierung verlor die Kirche ihren Einfluss auf Schule und Recht.', true, 38),
  (153, 'Instrumentalisierung', 'Substantiv', 'Recht und Ethik', 'Die Nutzung einer Person oder Sache als Mittel für einen anderen Zweck.', 'Das Ausnutzen einer Person oder Sache als bloßes Mittel für fremde Zwecke.', 'Die Instrumentalisierung einzelner Schicksale für politische Werbung wurde scharf kritisiert.', 'Man warf der Kampagne die Instrumentalisierung des Leids der Opfer vor.', true, 29),
  (154, 'Polarisierung', 'Substantiv', 'Politik und Gesellschaft', 'Die zunehmende Aufteilung in stark gegensätzliche Lager.', 'Das Auseinanderdriften einer Gesellschaft in verhärtete, gegnerische Lager.', 'Die Polarisierung erschwerte Kompromisse, obwohl viele Sachfragen lösbar gewesen wären.', 'Die Debatte trieb die Polarisierung so weit, dass ein Gespräch kaum noch möglich war.', true, 76),
  (155, 'Radikalisierung', 'Substantiv', 'Politik und Gesellschaft', 'Ein Prozess, in dem Positionen immer extremer werden und gemäßigte Lösungen an Bedeutung verlieren.', null, 'Die Radikalisierung begann mit einfachen Feindbildern und steigerte sich schrittweise.', null, false, null),
  (156, 'normativ', 'Adjektiv', 'Recht und Ethik', 'Vorschreibend oder bewertend; darauf bezogen, wie etwas sein soll.', 'Bezogen auf das, was gelten oder sein soll, statt auf das bloß Vorhandene.', 'Die Aussage war normativ, weil sie nicht nur beschrieb, sondern eine Pflicht formulierte.', '„Alle sollen gleich behandelt werden“ ist eine normative Forderung, keine Tatsachenaussage.', true, 39),
  (157, 'deskriptiv', 'Adjektiv', 'Recht und Ethik', 'Rein beschreibend; darauf bezogen, wie etwas tatsächlich ist.', 'Bloß beschreibend, wie etwas tatsächlich ist, ohne es zu bewerten.', 'Die Untersuchung blieb deskriptiv und gab keine moralische Empfehlung ab.', 'Der Bericht blieb streng deskriptiv und enthielt sich jeder Empfehlung.', true, 49),
  (158, 'Deontologie', 'Substantiv', 'Recht und Ethik', 'Eine Ethik, die Handlungen nach Pflichten und Regeln beurteilt, nicht nur nach ihren Folgen.', 'Eine Ethik, die Handlungen nach Pflichten und Regeln beurteilt, nicht nach ihren Folgen.', 'Aus deontologischer Sicht kann eine Lüge auch dann falsch sein, wenn sie nützlich wäre.', 'Aus Sicht der Deontologie bleibt Lügen auch dann verboten, wenn es Vorteile brächte.', true, 59),
  (159, 'Utilitarismus', 'Substantiv', 'Recht und Ethik', 'Eine Ethik, die Handlungen danach bewertet, wie viel Wohlergehen sie insgesamt erzeugen.', 'Eine Ethik, die jene Handlung für richtig hält, die das größte Wohl für die meisten schafft.', 'Der Utilitarismus könnte eine Entscheidung unterstützen, wenn sie vielen Menschen deutlich hilft.', 'Der Utilitarismus rechtfertigt eine Maßnahme, wenn ihr Nutzen den Schaden insgesamt überwiegt.', true, 69),
  (160, 'Kollektivismus', 'Substantiv', 'Recht und Ethik', 'Eine Haltung, die Ziele und Interessen der Gemeinschaft stärker als die des Einzelnen gewichtet.', 'Eine Haltung, die dem Wohl der Gemeinschaft Vorrang vor den Interessen des Einzelnen gibt.', 'Kollektivismus kann Zusammenhalt fördern, aber individuelle Freiheit begrenzen.', 'Im Kollektivismus zählt weniger der persönliche Erfolg als der Nutzen für die Gruppe.', true, 79),
  (161, 'Individualismus', 'Substantiv', 'Recht und Ethik', 'Eine Haltung, die Selbstbestimmung und Rechte des Einzelnen besonders betont.', 'Eine Haltung, die die Freiheit und den Eigenwert des einzelnen Menschen in den Mittelpunkt stellt.', 'Der Individualismus der Gesellschaft zeigte sich in der hohen Bedeutung persönlicher Wahlfreiheit.', 'Der westliche Individualismus betont das Recht, den eigenen Lebensweg selbst zu wählen.', true, 89),
  (162, 'Opportunismus', 'Substantiv', 'Politik und Gesellschaft', 'Die Anpassung der eigenen Position an den unmittelbaren Vorteil statt an feste Grundsätze.', null, 'Sein plötzlicher Kurswechsel wirkte wie Opportunismus.', null, false, null),
  (163, 'Dogmatismus', 'Substantiv', 'Politik und Gesellschaft', 'Das starre Festhalten an Überzeugungen ohne Bereitschaft zur Prüfung oder Korrektur.', null, 'Dogmatismus verhindert Lernen, weil Gegenargumente von vornherein abgewiesen werden.', null, false, null),
  (164, 'Orthodoxie', 'Substantiv', 'Kultur und Geschichte', 'Das strenge Festhalten an einer offiziell anerkannten Lehre oder Auslegung.', 'Das strenge Festhalten an der überlieferten, für rein gehaltenen Lehre.', 'Die wirtschaftliche Orthodoxie der Partei ließ kaum Raum für abweichende Modelle.', 'Jede Abweichung von der Orthodoxie galt der Bewegung als Verrat.', true, 48),
  (165, 'Anomie', 'Substantiv', 'Recht und Ethik', 'Ein Zustand schwacher oder widersprüchlicher gesellschaftlicher Regeln und Orientierung.', 'Ein Zustand, in dem verbindliche Normen fehlen oder ihre Kraft verlieren.', 'In Zeiten schneller Umbrüche kann Anomie entstehen, weil alte Normen verschwinden und neue noch fehlen.', 'Nach dem Zusammenbruch der alten Ordnung breitete sich eine gefährliche Anomie aus.', true, 99),
  (166, 'Devianz', 'Substantiv', 'Recht und Ethik', 'Verhalten, das von geltenden sozialen Normen abweicht.', 'Verhalten, das von den geltenden Normen einer Gruppe deutlich abweicht.', 'Ob ein Verhalten als Devianz gilt, hängt stark vom historischen und kulturellen Umfeld ab.', 'Was in der einen Gemeinschaft als Devianz gilt, ist in einer anderen völlig normal.', true, 108),
  (167, 'Distinktion', 'Substantiv', 'Politik und Gesellschaft', 'Die bewusste Abgrenzung, durch die Unterschiede und sozialer Status sichtbar gemacht werden.', null, 'Die teure Kleidung diente nicht nur dem Nutzen, sondern auch der Distinktion.', null, false, null),
  (168, 'Stratifikation', 'Substantiv', 'Wirtschaft und Organisation', 'Die dauerhafte Gliederung einer Gesellschaft in soziale Schichten.', 'Die Schichtung einer Gesellschaft in über- und untergeordnete Ränge.', 'Die Stratifikation zeigte sich in ungleichen Bildungs- und Aufstiegschancen.', 'Die soziale Stratifikation zeigte sich schon daran, welche Schule ein Kind besuchte.', true, 27),
  (169, 'Proliferation', 'Substantiv', 'Wirtschaft und Organisation', 'Die schnelle Ausbreitung oder starke Vermehrung von etwas.', 'Die rasche, oft unkontrollierte Ausbreitung oder Vermehrung von etwas.', 'Die Proliferation schwer kontrollierbarer Informationsquellen erhöhte das Risiko von Falschmeldungen.', 'Die Proliferation von Zwischenhändlern trieb den Endpreis in die Höhe.', true, 37),
  (170, 'Bürokratisierung', 'Substantiv', 'Wirtschaft und Organisation', 'Die zunehmende Regelung durch formale Verfahren, Zuständigkeiten und Dokumentation.', 'Die zunehmende Durchdringung von Abläufen mit festen Regeln, Zuständigkeiten und Formularen.', 'Die Bürokratisierung sollte Fairness schaffen, machte den Ablauf aber zugleich langsamer.', 'Die wachsende Bürokratisierung machte selbst kleine Anschaffungen zu einem langwierigen Verfahren.', true, 47),
  (171, 'Zentralisierung', 'Substantiv', 'Wirtschaft und Organisation', 'Die Bündelung von Entscheidungen und Zuständigkeiten an einer übergeordneten Stelle.', 'Das Bündeln von Entscheidungen und Befugnissen an einer obersten Stelle.', 'Durch Zentralisierung wurden Standards vereinheitlicht, lokale Unterschiede aber weniger beachtet.', 'Die Zentralisierung des Einkaufs sollte im Konzern Kosten senken.', true, 57),
  (172, 'Dezentralisierung', 'Substantiv', 'Wirtschaft und Organisation', 'Die Verteilung von Entscheidungen und Zuständigkeiten auf mehrere Ebenen oder Orte.', 'Das Verteilen von Entscheidungen auf viele eigenständige Einheiten.', 'Dezentralisierung kann schnellere Entscheidungen vor Ort ermöglichen.', 'Durch Dezentralisierung erhielten die Filialen mehr Freiheit bei der Preisgestaltung.', true, 67),
  (173, 'Korporatismus', 'Substantiv', 'Wirtschaft und Organisation', 'Eine Ordnung, in der organisierte Verbände fest in politische Entscheidungen eingebunden sind.', null, 'Im Korporatismus verhandeln Staat, Arbeitgeberverbände und Gewerkschaften regelmäßig miteinander.', null, false, null),
  (174, 'Souveränität', 'Substantiv', 'Politik und Gesellschaft', 'Die höchste selbstständige Entscheidungsgewalt eines Staates oder einer Person.', 'Die oberste Entscheidungsgewalt eines Staates über sein eigenes Gebiet nach innen und außen.', 'Internationale Verträge begrenzen staatliche Souveränität freiwillig zugunsten gemeinsamer Regeln.', 'Der Vertrag berührte die Frage, wie viel Souveränität ein Land an ein Bündnis abgibt.', true, 86),
  (175, 'Repräsentation', 'Substantiv', 'Politik und Gesellschaft', 'Die Vertretung oder Darstellung von Personen, Gruppen oder Ideen.', 'Die Vertretung der Interessen vieler durch gewählte Stellvertreter.', 'Politische Repräsentation bedeutet, dass Gewählte Interessen der Bevölkerung in Entscheidungen einbringen.', 'Man kritisierte, dass die Repräsentation der Jüngeren im Parlament zu schwach sei.', true, 96),
  (176, 'Diskurs', 'Substantiv', 'Politik und Gesellschaft', 'Ein gesellschaftlicher Zusammenhang, in dem über ein Thema gesprochen und Bedeutung erzeugt wird.', null, 'Der öffentliche Diskurs über Leistung veränderte sich mit den wirtschaftlichen Bedingungen.', null, false, null),
  (177, 'Diskursformation', 'Substantiv', 'Politik und Gesellschaft', 'Ein Gefüge aus Regeln und Begriffen, das festlegt, wie ein Thema überhaupt besprochen werden kann.', null, 'Die Diskursformation der Zeit ließ bestimmte Fragen vernünftig und andere undenkbar erscheinen.', null, false, null),
  (178, 'Stigma', 'Substantiv', 'Politik und Gesellschaft', 'Ein negativ bewertetes Merkmal, das eine Person gesellschaftlich abwertet.', null, 'Das Stigma der Arbeitslosigkeit belastete ihn stärker als der finanzielle Verlust.', null, false, null),
  (179, 'Utopie', 'Substantiv', 'Kultur und Geschichte', 'Die Vorstellung einer idealen, bisher nicht verwirklichten Gesellschaft.', 'Der Entwurf einer idealen Gesellschaft, die so noch nirgends verwirklicht ist.', 'Die Utopie entwarf eine gerechte Ordnung, erklärte aber kaum den Weg dorthin.', 'Sein Roman zeichnete die Utopie einer Welt ohne Geld und Besitz.', true, 58),
  (180, 'Dystopie', 'Substantiv', 'Kultur und Geschichte', 'Die Darstellung einer bedrückenden oder gefährlichen zukünftigen Gesellschaft.', 'Das Gegenbild zur Utopie: eine erschreckende Zukunftsgesellschaft als Warnung.', 'Die Dystopie zeigte, wie Bequemlichkeit schrittweise in vollständige Überwachung umschlagen konnte.', 'In der Dystopie überwachte ein allgegenwärtiger Staat jeden Gedanken der Bürger.', true, 68),
  (181, 'Allegorie', 'Substantiv', 'Sprache und Rhetorik', 'Eine längere bildhafte Darstellung, bei der etwas Sichtbares für einen abstrakten Gedanken steht.', 'Eine durchgehende Bildrede, in der ein abstrakter Gedanke als Figur oder Geschichte dargestellt wird.', 'Die Figur der blinden Justitia ist eine Allegorie der unparteiischen Gerechtigkeit.', 'Die Justitia mit Waage und verbundenen Augen ist eine Allegorie der Gerechtigkeit.', true, 3),
  (182, 'Allusion', 'Substantiv', 'Sprache und Rhetorik', 'Eine indirekte Anspielung auf einen bekannten Text, eine Person oder ein Ereignis.', null, 'Die Allusion auf den Mythos war nur für Leser mit entsprechendem Vorwissen erkennbar.', null, false, null),
  (183, 'Anachronismus', 'Substantiv', 'Kultur und Geschichte', 'Etwas, das zeitlich nicht in den dargestellten Zusammenhang passt.', 'Etwas, das nicht in seine Zeit passt, weil es einer anderen Epoche angehört.', 'Ein Smartphone in einem Mittelalterfilm wäre ein offensichtlicher Anachronismus.', 'Die Armbanduhr am Arm des Römers war ein peinlicher Anachronismus im Film.', true, 78),
  (184, 'Antithese', 'Substantiv', 'Sprache und Rhetorik', 'Die pointierte Gegenüberstellung entgegengesetzter Gedanken.', 'Die wirkungsvolle Gegenüberstellung zweier gegensätzlicher Gedanken.', 'Die Antithese „Freiheit statt Kontrolle“ verdichtete den Konflikt auf zwei Pole.', '„Der eine schuftet, der andere prasst“ setzt die Ungleichheit als Antithese in Szene.', true, 13),
  (185, 'Aphorismus', 'Substantiv', 'Sprache und Rhetorik', 'Ein kurzer, zugespitzter Satz, der einen Gedanken einprägsam ausdrückt.', 'Ein kurzer, zugespitzter Gedanke, der eine Einsicht pointiert auf den Punkt bringt.', 'Der Aphorismus wirkte einfach, eröffnete aber bei genauerem Lesen mehrere Deutungen.', '„Wer nichts weiß, muss alles glauben“ ist ein bekannter Aphorismus.', true, 23),
  (186, 'Chiasmus', 'Substantiv', 'Sprache und Rhetorik', 'Eine überkreuzte Satzstruktur nach dem Muster A-B-B-A.', null, 'Der Satz „Die Kunst ist lang, und kurz ist unser Leben“ enthält einen Chiasmus.', null, false, null),
  (187, 'Duktus', 'Substantiv', 'Sprache und Rhetorik', 'Die charakteristische Art, wie jemand spricht, schreibt oder gestaltet.', null, 'Der sachliche Duktus des Berichts kontrastierte mit seinem dramatischen Inhalt.', null, false, null),
  (188, 'Ellipse', 'Substantiv', 'Sprache und Rhetorik', 'Ein sprachlicher Ausdruck, bei dem leicht ergänzbare Wörter ausgelassen werden.', null, 'Die Ellipse „Je früher, desto besser“ ist trotz fehlender Verben verständlich.', null, false, null),
  (189, 'Euphemismus', 'Substantiv', 'Sprache und Rhetorik', 'Eine beschönigende Bezeichnung für etwas Unangenehmes oder Härteres.', 'Eine beschönigende Umschreibung, die etwas Unangenehmes milder klingen lässt.', '„Freisetzung von Personal“ ist ein Euphemismus für Entlassungen.', '„Freisetzung von Mitarbeitern“ ist ein Euphemismus für Entlassungen.', true, 33),
  (190, 'Exegese', 'Substantiv', 'Sprache und Rhetorik', 'Die sorgfältige Auslegung eines schwierigen oder bedeutenden Textes.', null, 'Die Exegese untersuchte Wortwahl, historischen Hintergrund und mögliche Lesarten.', null, false, null),
  (191, 'Exkurs', 'Substantiv', 'Sprache und Rhetorik', 'Eine kurze Abschweifung vom Hauptthema, die zusätzliche Zusammenhänge erklärt.', null, 'In einem Exkurs erläuterte der Autor die historische Entstehung des Begriffs.', null, false, null),
  (192, 'Hyperbel', 'Substantiv', 'Sprache und Rhetorik', 'Eine bewusste, starke Übertreibung zur Verstärkung einer Aussage.', 'Eine bewusste Übertreibung, die eine Aussage verstärken soll.', '„Ich habe dir das tausendmal gesagt“ ist eine Hyperbel.', '„Ich habe dir das schon tausendmal gesagt“ ist eine typische Hyperbel.', true, 43),
  (193, 'Litotes', 'Substantiv', 'Sprache und Rhetorik', 'Eine Untertreibung, bei der das Gegenteil verneint wird.', null, 'Mit „nicht ganz unbegabt“ verwendete sie eine Litotes, um vorsichtig zu loben.', null, false, null),
  (194, 'Denotation', 'Substantiv', 'Sprache und Rhetorik', 'Die sachliche Grundbedeutung eines Wortes ohne zusätzliche Gefühle oder Wertungen.', null, 'Die Denotation von „Fuchs“ bezeichnet zunächst das Tier, unabhängig von der Vorstellung von Schlauheit.', null, false, null),
  (195, 'Metapher', 'Substantiv', 'Sprache und Rhetorik', 'Ein bildhafter Ausdruck, bei dem ein Wort auf einen anderen Bereich übertragen wird.', 'Ein sprachliches Bild, das einen Begriff durch einen anderen ersetzt, um eine Ähnlichkeit auszudrücken.', 'Die Metapher vom „Datenstrom“ macht unsichtbare digitale Vorgänge anschaulich.', 'Mit der Metapher vom „Herbst des Lebens“ meinte sie das nahende Alter.', true, 53),
  (196, 'Metonymie', 'Substantiv', 'Sprache und Rhetorik', 'Die Ersetzung eines Begriffs durch einen sachlich eng verbundenen anderen Begriff.', 'Eine Ersetzung, bei der man eine Sache durch etwas eng damit Verbundenes benennt.', 'In „Berlin entscheidet“ steht die Stadt als Metonymie für die Bundesregierung.', 'Wenn man sagt „das Weiße Haus erklärte“, steht die Metonymie für die US-Regierung.', true, 63),
  (197, 'Neologismus', 'Substantiv', 'Sprache und Rhetorik', 'Ein neu gebildetes oder neu verwendetes Wort.', 'Ein neu gebildetes Wort, das in den Sprachgebrauch eintritt.', '„Doomscrolling“ ist ein Neologismus für das endlose Lesen negativer Nachrichten.', '„Klimakleber“ war vor wenigen Jahren noch ein Neologismus.', true, 73),
  (198, 'Paradoxon', 'Substantiv', 'Sprache und Rhetorik', 'Eine Aussage, die widersprüchlich wirkt, aber eine tiefere Wahrheit enthalten kann.', 'Eine scheinbar widersinnige Aussage, die bei näherem Hinsehen doch einen wahren Kern enthält.', 'Das Paradoxon „Weniger ist mehr“ ergibt in vielen Gestaltungssituationen Sinn.', '„Ich weiß, dass ich nichts weiß“ ist das berühmte Paradoxon des Sokrates.', true, 83),
  (199, 'Paraphrase', 'Substantiv', 'Sprache und Rhetorik', 'Die Wiedergabe eines Gedankens mit anderen Worten.', null, 'Durch die Paraphrase zeigte sie, dass sie den schwierigen Absatz verstanden hatte.', null, false, null),
  (200, 'Periphrase', 'Substantiv', 'Sprache und Rhetorik', 'Eine umschreibende Bezeichnung statt des direkten Wortes.', null, '„Das Land der aufgehenden Sonne“ ist eine Periphrase für Japan.', null, false, null),
  (201, 'Polysemie', 'Substantiv', 'Sprache und Rhetorik', 'Die Eigenschaft eines Wortes, mehrere miteinander verbundene Bedeutungen zu haben.', null, 'Die Polysemie von „Schloss“ umfasst sowohl ein Gebäude als auch einen Verschluss.', null, false, null),
  (202, 'Semantik', 'Substantiv', 'Sprache und Rhetorik', 'Die Bedeutung von Wörtern, Sätzen und Zeichen.', 'Der Bereich der Sprachwissenschaft, der sich mit der Bedeutung von Wörtern und Sätzen befasst.', 'Grammatikalisch war der Satz korrekt, doch seine Semantik blieb unklar.', 'Ein Streit um Semantik entzündete sich daran, was genau „fair“ bedeuten soll.', true, 93),
  (203, 'Symbolik', 'Substantiv', 'Sprache und Rhetorik', 'Die Verwendung von Zeichen oder Bildern mit übertragener Bedeutung.', null, 'Die Symbolik des zerbrochenen Spiegels verwies auf den Verlust der eigenen Identität.', null, false, null),
  (204, 'Synekdoche', 'Substantiv', 'Sprache und Rhetorik', 'Eine Ausdrucksweise, bei der ein Teil für das Ganze oder das Ganze für einen Teil steht.', null, 'In „Wir brauchen mehr Hände“ steht „Hände“ als Synekdoche für Arbeitskräfte.', null, false, null),
  (205, 'Topos', 'Substantiv', 'Sprache und Rhetorik', 'Ein wiederkehrendes Denkbild oder bekanntes Motiv in Sprache und Kultur.', null, 'Der Topos vom einsamen Genie taucht in vielen Künstlerbiografien auf.', null, false, null),
  (206, 'Zynismus', 'Substantiv', 'Sprache und Rhetorik', 'Eine Haltung, die Ideale verspottet und eigennützige Motive als selbstverständlich annimmt.', null, 'Sein Zynismus ließ jede Hilfeleistung wie bloße Selbstdarstellung erscheinen.', null, false, null),
  (207, 'Pathos', 'Substantiv', 'Sprache und Rhetorik', 'Eine feierliche oder stark gefühlsbetonte Ausdrucksweise.', 'Der Gefühlsappell einer Rede, der das Publikum ergreifen und mitreißen soll.', 'Das große Pathos der Rede passte kaum zu dem kleinen Anlass.', 'Mit spürbarem Pathos beschwor der Redner den Zusammenhalt der Gemeinschaft.', true, 103),
  (208, 'Ethos', 'Substantiv', 'Sprache und Rhetorik', 'Die glaubwürdig wirkende Haltung und der moralische Charakter einer sprechenden Person.', null, 'Ihr ruhiges Ethos überzeugte stärker als die vielen Zahlen.', null, false, null),
  (209, 'Logos', 'Substantiv', 'Sprache und Rhetorik', 'Die Überzeugungskraft durch nachvollziehbare Gründe und Belege.', null, 'Der Logos der Argumentation beruhte auf klaren Daten und sauberen Schlüssen.', null, false, null),
  (210, 'Narratologie', 'Substantiv', 'Sprache und Rhetorik', 'Die wissenschaftliche Untersuchung davon, wie Geschichten aufgebaut und erzählt werden.', null, 'Die Narratologie unterscheidet zwischen dem Geschehen und der Art seiner Darstellung.', null, false, null),
  (211, 'Etymologie', 'Substantiv', 'Kultur und Geschichte', 'Die Herkunft und geschichtliche Entwicklung eines Wortes.', 'Die Erforschung der Herkunft und Bedeutungsgeschichte von Wörtern.', 'Die Etymologie des Begriffs zeigte, dass seine ursprüngliche Bedeutung deutlich enger war.', 'Die Etymologie führt „Fenster“ auf das lateinische „fenestra“ zurück.', true, 88),
  (212, 'Idiomatismus', 'Substantiv', 'Sprache und Rhetorik', 'Eine feste sprachliche Wendung, deren Bedeutung nicht direkt aus den Einzelwörtern folgt.', null, '„Ins Gras beißen“ ist ein Idiomatismus und darf nicht wörtlich verstanden werden.', null, false, null),
  (213, 'implizit', 'Adjektiv', 'Sprache und Rhetorik', 'Mitgemeint, aber nicht ausdrücklich ausgesprochen.', null, 'Seine Zustimmung war implizit, weil er ohne Widerspruch mit der Umsetzung begann.', null, false, null),
  (214, 'explizit', 'Adjektiv', 'Sprache und Rhetorik', 'Klar und ausdrücklich formuliert.', null, 'Die Regel verbot explizit jede Weitergabe der Zugangsdaten.', null, false, null),
  (215, 'Kontextualisierung', 'Substantiv', 'Sprache und Rhetorik', 'Die Einordnung einer Aussage in ihren zeitlichen, sozialen oder sachlichen Zusammenhang.', null, 'Erst die Kontextualisierung erklärte, warum der Satz damals anders verstanden wurde.', null, false, null),
  (216, 'Dekonstruktion', 'Substantiv', 'Sprache und Rhetorik', 'Eine genaue Analyse, die verborgene Gegensätze und Voraussetzungen eines Textes offenlegt.', null, 'Die Dekonstruktion zeigte, dass der Text die angeblich klare Grenze selbst immer wieder unterlief.', null, false, null),
  (217, 'Hermeneutik', 'Substantiv', 'Sprache und Rhetorik', 'Die Lehre vom Verstehen und Auslegen von Texten, Handlungen und Bedeutungen.', null, 'Hermeneutik berücksichtigt, dass Vorwissen jede Interpretation mitprägt.', null, false, null),
  (218, 'Mimesis', 'Substantiv', 'Kultur und Geschichte', 'Die künstlerische Nachahmung oder Darstellung von Wirklichkeit.', 'Die künstlerische Nachahmung der Wirklichkeit als Grundprinzip der Darstellung.', 'Der Roman erzeugt Mimesis, ohne die Wirklichkeit einfach zu kopieren.', 'Die antike Theorie sah in der Mimesis den Kern jeder Malerei und Dichtung.', true, 98),
  (219, 'Intertextualität', 'Substantiv', 'Kultur und Geschichte', 'Die Beziehung eines Textes zu anderen Texten durch Zitate, Motive oder Anspielungen.', 'Das Verweisen eines Textes auf andere Texte durch Zitate, Anspielungen oder Motive.', 'Die Intertextualität des Romans wurde durch zahlreiche Verweise auf antike Mythen sichtbar.', 'Der Roman lebt von einer Intertextualität, die ständig auf alte Mythen anspielt.', true, 107),
  (220, 'Metanarrativ', 'Substantiv', 'Sprache und Rhetorik', 'Eine umfassende Erzählung, die viele Ereignisse durch ein großes Deutungsmuster erklärt.', null, 'Der Glaube an stetigen Fortschritt kann als Metanarrativ moderner Gesellschaften verstanden werden.', null, false, null),
  (221, 'adäquat', 'Adjektiv', 'Allgemeine Bildungssprache', 'Angemessen und genau passend für die jeweilige Situation.', 'Einer Sache genau angemessen, ohne zu viel oder zu wenig zu sein.', 'Eine pauschale Antwort wäre der Komplexität des Problems nicht adäquat.', 'Für den Anlass wählte sie eine adäquate, zurückhaltende Kleidung.', true, 10),
  (222, 'arbiträr', 'Adjektiv', 'Allgemeine Bildungssprache', 'Ohne zwingenden Grund festgelegt und grundsätzlich auch anders möglich.', 'Ohne sachlichen Grund festgelegt, allein auf Willkür oder Übereinkunft beruhend.', 'Die Grenze wirkte arbiträr, weil keine sachliche Begründung für ihren Verlauf erkennbar war.', 'Dass Rot „Stopp“ bedeutet, ist arbiträr und hätte auch anders vereinbart werden können.', true, 20),
  (223, 'antiquiert', 'Adjektiv', 'Allgemeine Bildungssprache', 'Veraltet und nicht mehr zeitgemäß.', null, 'Das Rollenbild erschien vielen Jugendlichen antiquiert.', null, false, null),
  (224, 'akzidentiell', 'Adjektiv', 'Allgemeine Bildungssprache', 'Zufällig oder nebensächlich vorhanden, ohne zum notwendigen Wesen einer Sache zu gehören.', null, 'Die Farbe ist für die Funktion des Geräts akzidentiell.', null, false, null),
  (225, 'immanent', 'Adjektiv', 'Allgemeine Bildungssprache', 'Innerhalb eines Systems liegend und aus ihm selbst hervorgehend.', 'Einer Sache innewohnend, aus ihr selbst hervorgehend statt von außen hinzukommend.', 'Der Konflikt war dem Geschäftsmodell immanent und nicht nur Folge eines einzelnen Fehlers.', 'Dem Projekt war von Beginn an ein immanenter Zielkonflikt eingeschrieben.', true, 30),
  (226, 'sukzessiv', 'Adjektiv', 'Allgemeine Bildungssprache', 'Schrittweise nacheinander erfolgend.', 'Schritt für Schritt aufeinanderfolgend, nicht auf einmal.', 'Die alten Geräte wurden sukzessiv durch effizientere Modelle ersetzt.', 'Die Reformen wurden sukzessiv über mehrere Jahre eingeführt.', true, 40),
  (227, 'simultan', 'Adjektiv', 'Allgemeine Bildungssprache', 'Zur gleichen Zeit stattfindend.', 'Zur gleichen Zeit ablaufend, gleichzeitig.', 'Die beiden Entwicklungen verliefen simultan, ohne zwingend voneinander verursacht zu sein.', 'Die Dolmetscherin übertrug die Rede nahezu simultan ins Deutsche.', true, 50),
  (228, 'prospektiv', 'Adjektiv', 'Allgemeine Bildungssprache', 'Auf zukünftige Entwicklungen gerichtet.', 'Nach vorn, in die Zukunft gerichtet.', 'Die prospektive Studie begleitet die Teilnehmenden über mehrere Jahre.', 'Die Studie war prospektiv angelegt und begleitete die Teilnehmer über zehn Jahre.', true, 60),
  (229, 'retrospektiv', 'Adjektiv', 'Allgemeine Bildungssprache', 'Rückblickend auf bereits vergangene Ereignisse gerichtet.', 'Zurückblickend, aus der Sicht auf bereits Vergangenes.', 'Retrospektiv wirkte die Entscheidung riskanter, als sie im damaligen Wissensstand erschien.', 'Retrospektiv erschienen die damaligen Sorgen weit übertrieben.', true, 70),
  (230, 'rekursiv', 'Adjektiv', 'Allgemeine Bildungssprache', 'So aufgebaut, dass ein Vorgang auf sich selbst oder eine kleinere Version desselben Vorgangs zurückgreift.', null, 'Die rekursive Funktion löste das Problem, indem sie es wiederholt in kleinere Teilprobleme zerlegte.', null, false, null),
  (231, 'konstitutiv', 'Adjektiv', 'Allgemeine Bildungssprache', 'Grundlegend dafür, dass etwas überhaupt in seiner Form entsteht oder besteht.', 'Für etwas grundlegend bestimmend, so dass es ohne dieses Merkmal gar nicht bestünde.', 'Vertrauen ist konstitutiv für jede langfristige Zusammenarbeit.', 'Das Vertrauen der Bürger ist konstitutiv für jede Demokratie.', true, 80),
  (232, 'Manifestation', 'Substantiv', 'Allgemeine Bildungssprache', 'Das sichtbare oder erkennbare Auftreten eines zuvor verborgenen Vorgangs.', 'Das sichtbare Zutagetreten von etwas zuvor Verborgenem.', 'Der plötzliche Leistungsabfall war eine Manifestation der länger andauernden Überlastung.', 'Der Streik war die Manifestation einer lange schwelenden Unzufriedenheit.', true, 90),
  (233, 'Fragmentierung', 'Substantiv', 'Allgemeine Bildungssprache', 'Die Aufteilung eines zusammenhängenden Ganzen in viele getrennte Teile.', null, 'Die Fragmentierung der Informationen erschwerte einen vollständigen Überblick.', null, false, null),
  (234, 'Akkumulation', 'Substantiv', 'Wirtschaft und Organisation', 'Die schrittweise Ansammlung oder Vermehrung über längere Zeit.', 'Das allmähliche Anhäufen von Kapital, Gütern oder Ressourcen.', 'Die Akkumulation kleiner Fehler führte schließlich zu einem größeren Ausfall.', 'Die Akkumulation von Rücklagen erlaubte dem Betrieb später eine große Investition.', true, 77),
  (235, 'Diffusion', 'Substantiv', 'Wirtschaft und Organisation', 'Die allmähliche Ausbreitung von Stoffen, Ideen oder Neuerungen.', null, 'Die Diffusion der neuen Technik verlief zunächst langsam und beschleunigte sich später.', null, false, null),
  (236, 'Adaption', 'Substantiv', 'Wirtschaft und Organisation', 'Die Anpassung an neue Bedingungen oder die Übertragung in eine andere Form.', 'Die Anpassung an veränderte Bedingungen, um leistungs- oder überlebensfähig zu bleiben.', 'Die filmische Adaption veränderte mehrere Szenen des Romans.', 'Die schnelle Adaption an das Online-Geschäft rettete den kleinen Verlag.', true, 87),
  (237, 'Transformation', 'Substantiv', 'Allgemeine Bildungssprache', 'Eine grundlegende Veränderung von Struktur, Form oder Zustand.', 'Eine tiefgreifende Umgestaltung, die den Charakter einer Sache verändert.', 'Die digitale Transformation betraf nicht nur Werkzeuge, sondern auch Arbeitsabläufe und Rollen.', 'Die digitale Transformation krempelte die Arbeitsweise der Behörde von Grund auf um.', true, 100),
  (238, 'Transgression', 'Substantiv', 'Allgemeine Bildungssprache', 'Die bewusste Überschreitung einer sozialen, moralischen oder künstlerischen Grenze.', null, 'Die Transgression sollte provozieren und die geltenden Regeln sichtbar machen.', null, false, null),
  (239, 'Disruption', 'Substantiv', 'Wirtschaft und Organisation', 'Eine tiefgreifende Unterbrechung, die bestehende Abläufe oder Märkte grundlegend verändert.', 'Ein Umbruch, bei dem eine Neuerung bestehende Märkte oder Abläufe grundlegend verdrängt.', 'Streaming führte zu einer Disruption traditioneller Vertriebsmodelle.', 'Das Smartphone löste eine Disruption der gesamten Fotobranche aus.', true, 97),
  (240, 'Volatilität', 'Substantiv', 'Wirtschaft und Organisation', 'Die Stärke und Häufigkeit kurzfristiger Schwankungen.', 'Das Ausmaß, in dem Preise oder Werte in kurzer Zeit stark schwanken.', 'Die hohe Volatilität des Preises machte verlässliche Planung schwierig.', 'Die hohe Volatilität der Aktie schreckte vorsichtige Anleger ab.', true, 106),
  (241, 'Friktion', 'Substantiv', 'Wirtschaft und Organisation', 'Ein Widerstand oder Reibungsverlust, der Abläufe erschwert oder verlangsamt.', null, 'Unklare Zuständigkeiten erzeugten Friktion zwischen den beiden Teams.', null, false, null),
  (242, 'Latenz', 'Substantiv', 'Allgemeine Bildungssprache', 'Die Verzögerung zwischen einem Auslöser und der sichtbaren Reaktion.', null, 'Die hohe Latenz machte die Steuerung des Systems unpräzise.', null, false, null),
  (243, 'Genese', 'Substantiv', 'Kultur und Geschichte', 'Die Entstehung und schrittweise Entwicklung eines Sachverhalts.', 'Die Entstehung und schrittweise Entwicklung einer Sache von ihrem Ursprung an.', 'Die Genese des Konflikts ließ sich bis zu einer frühen Fehlentscheidung zurückverfolgen.', 'Das Buch schildert die Genese der Demokratie von der antiken Polis bis heute.', true, 110),
  (244, 'Prozessualität', 'Substantiv', 'Allgemeine Bildungssprache', 'Die Eigenschaft, nicht statisch zu sein, sondern sich fortlaufend zu entwickeln.', null, 'Die Prozessualität von Identität bedeutet, dass sie sich durch Erfahrungen ständig verändert.', null, false, null),
  (245, 'Komplexität', 'Substantiv', 'Allgemeine Bildungssprache', 'Das Zusammenwirken vieler Teile und Beziehungen, wodurch einfache Erklärungen nicht ausreichen.', 'Der Grad, in dem viele Teile so verflochten sind, dass sich das Ganze schwer überblicken lässt.', 'Die Komplexität des Systems machte kleine Eingriffe schwer vorhersehbar.', 'Die Komplexität des Steuerrechts überfordert selbst manche Fachleute.', true, 109),
  (246, 'Heterogenität', 'Substantiv', 'Allgemeine Bildungssprache', 'Die Verschiedenartigkeit der Bestandteile einer Gruppe oder Menge.', null, 'Die Heterogenität der Lerngruppe erforderte unterschiedliche Aufgaben und Erklärungen.', null, false, null),
  (247, 'Homogenität', 'Substantiv', 'Allgemeine Bildungssprache', 'Die weitgehende Gleichartigkeit der Bestandteile einer Gruppe oder Menge.', null, 'Die scheinbare Homogenität der Gruppe verdeckte wichtige individuelle Unterschiede.', null, false, null),
  (248, 'inkommensurabel', 'Adjektiv', 'Allgemeine Bildungssprache', 'Nicht sinnvoll mit demselben Maßstab vergleichbar.', null, 'Künstlerische Qualität und finanzieller Gewinn sind teilweise inkommensurabel.', null, false, null),
  (249, 'exogen', 'Adjektiv', 'Allgemeine Bildungssprache', 'Von außen verursacht oder in ein System hineingetragen.', null, 'Der Nachfrageeinbruch war exogen, weil er durch ein internationales Ereignis ausgelöst wurde.', null, false, null),
  (250, 'endogen', 'Adjektiv', 'Allgemeine Bildungssprache', 'Aus inneren Bedingungen oder Vorgängen eines Systems heraus entstanden.', null, 'Das Wachstum war endogen und beruhte auf eigenen Verbesserungen des Unternehmens.', null, false, null)
