-- AUTOGENERIERT von build_catalog.mjs – nicht von Hand bearbeiten.
-- Seed der Warteliste public.word_queue mit allen 250 Vokabeln.
-- Idempotent: erneutes Ausführen aktualisiert nur den Katalogtext,
-- ändert aber keinen bereits gesetzten Verarbeitungsstatus.

on conflict (word) do update set
  position = excluded.position,
  part_of_speech = excluded.part_of_speech,
  category = excluded.category,
  definition = excluded.definition,
  definition2 = excluded.definition2,
  example = excluded.example,
  example2 = excluded.example2,
  enriched = excluded.enriched,
  activation_order = excluded.activation_order;
